      | `ResourceLimitExceeded of ResourceLimitExceeded.t 
      | `Unknown_operation_error of (string * string option) ]
    let make ?inferenceExperimentArn = fun () -> { inferenceExperimentArn }
    let error_of_json name json =
      match name with
      | "ResourceInUse" -> `ResourceInUse (ResourceInUse.of_json json)
      | "ResourceLimitExceeded" ->
          `ResourceLimitExceeded (ResourceLimitExceeded.of_json json)
      | name ->
          `Unknown_operation_error
            (name, (Some (Yojson.Safe.to_string json)))
    let error_of_xml name xml =
      match name with
      | "ResourceInUse" -> `ResourceInUse (ResourceInUse.of_xml xml)
      | "ResourceLimitExceeded" ->
          `ResourceLimitExceeded (ResourceLimitExceeded.of_xml xml)
      | name ->
          `Unknown_operation_error (name, (Some (Awso.Xml.to_string xml)))
    let error_to_json : error -> Yojson.Safe.t =
      function
      | `ResourceInUse e ->
          `Assoc
            [("error", (`String "ResourceInUse"));
            ("details", (ResourceInUse.to_json e))]
      | `ResourceLimitExceeded e ->
          `Assoc
            [("error", (`String "ResourceLimitExceeded"));
            ("details", (ResourceLimitExceeded.to_json e))]
      | `Unknown_operation_error (code, msg) ->
          `Assoc (("error", (`String code)) ::
            ((match msg with
              | None -> []
              | Some m -> [("message", (`String m))])))
    let to_value x =
      structure_to_value
        [("InferenceExperimentArn",
           (Option.map x.inferenceExperimentArn
              ~f:InferenceExperimentArn.to_value))]
    let to_query v = to_query to_value v
    let of_xml xml_arg0 =
      let inferenceExperimentArn =
        (Option.map ~f:InferenceExperimentArn.of_xml)
          (Xml.child xml_arg0 "InferenceExperimentArn") in
      make ?inferenceExperimentArn ()
    let of_string s = of_xml (Awso.Xml.parse_response s)[@@warning "-32"]
    let of_json json__ =
      let inferenceExperimentArn =
        field_map json__ "InferenceExperimentArn"
          InferenceExperimentArn.of_json in
      make ?inferenceExperimentArn ()
    let to_json v = composed_to_json to_value v
  end[@@ocaml.doc
       "Creates an inference experiment using the configurations specified in the request. Use this API to setup and schedule an experiment to compare model variants on a Amazon SageMaker inference endpoint. For more information about inference experiments, see Shadow tests. Amazon SageMaker begins your experiment at the scheduled time and routes traffic to your endpoint's model variants based on your specified configuration. While the experiment is in progress or after it has concluded, you can view metrics that compare your model variants. For more information, see View, monitor, and edit shadow tests."]
