:aws:lambda:us-east-2:266458841044:function:PRE-PassThrough arn:aws:lambda:us-west-2:081040173940:function:PRE-PassThrough arn:aws:lambda:ca-central-1:918755190332:function:PRE-PassThrough arn:aws:lambda:eu-west-1:568282634449:function:PRE-PassThrough arn:aws:lambda:eu-west-2:487402164563:function:PRE-PassThrough arn:aws:lambda:eu-central-1:203001061592:function:PRE-PassThrough arn:aws:lambda:ap-northeast-1:477331159723:function:PRE-PassThrough arn:aws:lambda:ap-northeast-2:845288260483:function:PRE-PassThrough arn:aws:lambda:ap-south-1:565803892007:function:PRE-PassThrough arn:aws:lambda:ap-southeast-1:377565633583:function:PRE-PassThrough arn:aws:lambda:ap-southeast-2:454466003867:function:PRE-PassThrough"];
      taskKeywords: TaskKeywords.t option
        [@ocaml.doc
          "Keywords used to describe the task so that workers on Amazon Mechanical Turk can discover the task."];
      taskTitle: TaskTitle.t
        [@ocaml.doc "A title for the task for your human workers."];
      taskDescription: TaskDescription.t
        [@ocaml.doc "A description of the task for your human workers."];
      numberOfHumanWorkersPerDataObject: NumberOfHumanWorkersPerDataObject.t
        [@ocaml.doc "The number of human workers that will label an object."];
      taskTimeLimitInSeconds: TaskTimeLimitInSeconds.t
        [@ocaml.doc
          "The amount of time that a worker has to complete a task. If you create a custom labeling job, the maximum value for this parameter is 8 hours (28,800 seconds). If you create a labeling job using a built-in task type the maximum for this parameter depends on the task type you use: For image and text labeling jobs, the maximum is 8 hours (28,800 seconds). For 3D point cloud and video frame labeling jobs, the maximum is 30 days (2952,000 seconds) for non-AL mode. For most users, the maximum is also 30 days."];
      taskAvailabilityLifetimeInSeconds:
        TaskAvailabilityLifetimeInSeconds.t option
        [@ocaml.doc
          "The length of time that a task remains available for labeling by human workers. The default and maximum values for this parameter depend on the type of workforce you use. If you choose the Amazon Mechanical Turk workforce, the maximum is 12 hours (43,200 seconds). The default is 6 hours (21,600 seconds). If you choose a private or vendor workforce, the default value is 30 days (2592,000 seconds) for non-AL mode. For most users, the maximum is also 30 days."];
      maxConcurrentTaskCount: MaxConcurrentTaskCount.t option
        [@ocaml.doc
