         (List.map
            ~f:(fun (x, y) ->
                  (CustomerMetadataKey.to_value x) |>
                    (fun x ->
                       (CustomerMetadataValue.to_value y) |>
                         (fun y -> (x, y))))))
        |> (fun x -> `Map x)
