module EndpointStatus =
  struct
    type nonrec t =
      | OutOfService 
      | Creating 
      | Updating 
      | SystemUpdating 
      | RollingBack 
      | InService 
      | Deleting 
      | Failed 
      | UpdateRollbackFailed 
      | Non_static_id of string 
    let make i = i
    let to_string =
      function
      | OutOfService -> "OutOfService"
      | Creating -> "Creating"
      | Updating -> "Updating"
      | SystemUpdating -> "SystemUpdating"
      | RollingBack -> "RollingBack"
      | InService -> "InService"
      | Deleting -> "Deleting"
      | Failed -> "Failed"
      | UpdateRollbackFailed -> "UpdateRollbackFailed"
      | Non_static_id s -> s
    let of_string =
      function
      | "OutOfService" -> OutOfService
      | "Creating" -> Creating
      | "Updating" -> Updating
      | "SystemUpdating" -> SystemUpdating
      | "RollingBack" -> RollingBack
      | "InService" -> InService
      | "Deleting" -> Deleting
      | "Failed" -> Failed
      | "UpdateRollbackFailed" -> UpdateRollbackFailed
      | x -> Non_static_id x
    let to_value x = `Enum (to_string x)
    let to_query v = to_query to_value v
    let to_header x = to_string x
    let of_xml xml_arg0 =
      of_string (string_of_xml ~kind:"enumeration EndpointStatus" xml_arg0)
    let of_json j = of_string (string_of_json ~kind:"EndpointStatus" j)
    let to_json = simple_to_json to_value
  end
