module TrainingJobStatus =
  struct
    type nonrec t =
      | InProgress 
      | Completed 
      | Failed 
      | Stopping 
      | Stopped 
      | Deleting 
      | Non_static_id of string 
    let make i = i
    let to_string =
      function
      | InProgress -> "InProgress"
      | Completed -> "Completed"
      | Failed -> "Failed"
      | Stopping -> "Stopping"
      | Stopped -> "Stopped"
      | Deleting -> "Deleting"
      | Non_static_id s -> s
    let of_string =
      function
      | "InProgress" -> InProgress
      | "Completed" -> Completed
      | "Failed" -> Failed
      | "Stopping" -> Stopping
      | "Stopped" -> Stopped
      | "Deleting" -> Deleting
      | x -> Non_static_id x
    let to_value x = `Enum (to_string x)
    let to_query v = to_query to_value v
    let to_header x = to_string x
    let of_xml xml_arg0 =
      of_string
        (string_of_xml ~kind:"enumeration TrainingJobStatus" xml_arg0)
    let of_json j = of_string (string_of_json ~kind:"TrainingJobStatus" j)
    let to_json = simple_to_json to_value
  end
