module ScheduleStatus =
  struct
    type nonrec t =
      | Pending 
      | Failed 
      | Scheduled 
      | Stopped 
      | Non_static_id of string 
    let make i = i
    let to_string =
      function
      | Pending -> "Pending"
      | Failed -> "Failed"
      | Scheduled -> "Scheduled"
      | Stopped -> "Stopped"
      | Non_static_id s -> s
    let of_string =
      function
      | "Pending" -> Pending
      | "Failed" -> Failed
      | "Scheduled" -> Scheduled
      | "Stopped" -> Stopped
      | x -> Non_static_id x
    let to_value x = `Enum (to_string x)
    let to_query v = to_query to_value v
    let to_header x = to_string x
    let of_xml xml_arg0 =
      of_string (string_of_xml ~kind:"enumeration ScheduleStatus" xml_arg0)
    let of_json j = of_string (string_of_json ~kind:"ScheduleStatus" j)
